import React from "react";

const NoteCard = ({ note, onOpenModal }) => {
  return (
    // Make the entire div clickable for better UX
    <div
      onClick={() => onOpenModal(note)} // Use the whole card to open the modal
      className="bg-white rounded-xl shadow-lg p-5 border-t-4 border-indigo-500 hover:shadow-xl transition-all duration-300 cursor-pointer transform hover:scale-[1.01]"
    >
      {/* 📝 Note Title */}
      <h3 className="text-xl font-bold text-gray-900 mb-2 truncate">
        {note.title || "Untitled Note"}
      </h3>

      {/* 📄 Note Content Preview */}
      <p className="text-gray-600 mb-4 text-sm line-clamp-3 h-[4.5em]">
        {note.preview || "preview Content"}
      </p>

      {/* 📅 Metadata/Date */}
      <div className="flex justify-between items-center border-t pt-3">
        <p className="text-xs text-gray-500 font-medium">
          Last Updated: 
        </p>

        {/* The 'View/Edit' button is optional if the whole card is clickable, but useful for clarity */}
        <span className="text-xs text-indigo-600 font-semibold hover:text-indigo-800 transition-colors">
          View Details →
        </span>
      </div>
    </div>
  );
};

export default NoteCard;
